#include <omp.h>
#include "common.h"

#ifdef RD_WG_SIZE_0_0
#define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
#define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
#define BLOCK_SIZE RD_WG_SIZE
#else
#define BLOCK_SIZE 16
#endif

extern int omp_num_threads;

static void lud_diagonal_block(float *m, int matrix_dim, int offset, int block_size)
{
    int i, j, tx;
    float shadow[BLOCK_SIZE * BLOCK_SIZE];

    for (i = 0; i < block_size; i++) {
        for (tx = 0; tx < block_size; tx++) {
            shadow[i * BLOCK_SIZE + tx] = m[(offset + i) * matrix_dim + offset + tx];
        }
    }

    for (i = 0; i < block_size - 1; i++) {
        for (tx = i + 1; tx < block_size; tx++) {
            for (j = 0; j < i; j++) {
                shadow[tx * BLOCK_SIZE + i] -=
                    shadow[tx * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + i];
            }
            shadow[tx * BLOCK_SIZE + i] /= shadow[i * BLOCK_SIZE + i];
        }

        for (tx = i + 1; tx < block_size; tx++) {
            for (j = 0; j < i + 1; j++) {
                shadow[(i + 1) * BLOCK_SIZE + tx] -=
                    shadow[(i + 1) * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + tx];
            }
        }
    }

    for (i = 0; i < block_size; i++) {
        for (tx = 0; tx < block_size; tx++) {
            m[(offset + i) * matrix_dim + offset + tx] = shadow[i * BLOCK_SIZE + tx];
        }
    }
}

static void lud_perimeter_row(float *m, int matrix_dim, int offset, int block_size,
                              int col_start, int col_block_size)
{
    int i, j, idx;

    for (idx = 0; idx < col_block_size; idx++) {
        for (i = 1; i < block_size; i++) {
            for (j = 0; j < i; j++) {
                m[(offset + i) * matrix_dim + col_start + idx] -=
                    m[(offset + i) * matrix_dim + offset + j] *
                    m[(offset + j) * matrix_dim + col_start + idx];
            }
        }
    }
}

static void lud_perimeter_col(float *m, int matrix_dim, int offset, int block_size,
                              int row_start, int row_block_size)
{
    int i, j, idx;

    for (idx = 0; idx < row_block_size; idx++) {
        for (i = 0; i < block_size; i++) {
            for (j = 0; j < i; j++) {
                m[(row_start + idx) * matrix_dim + offset + i] -=
                    m[(row_start + idx) * matrix_dim + offset + j] *
                    m[(offset + j) * matrix_dim + offset + i];
            }
            m[(row_start + idx) * matrix_dim + offset + i] /=
                m[(offset + i) * matrix_dim + offset + i];
        }
    }
}

static void lud_internal_block(float *m, int matrix_dim,
                               int row_start, int row_block_size,
                               int col_start, int col_block_size,
                               int offset, int block_size)
{
    int ty, tx, i;

    for (ty = 0; ty < row_block_size; ty++) {
        for (tx = 0; tx < col_block_size; tx++) {
            float sum = 0.0f;
            for (i = 0; i < block_size; i++) {
                sum += m[(row_start + ty) * matrix_dim + offset + i] *
                       m[(offset + i) * matrix_dim + col_start + tx];
            }
            m[(row_start + ty) * matrix_dim + col_start + tx] -= sum;
        }
    }
}

void lud_omp(float *m, int matrix_dim)
{
    int offset;

    if (m == 0 || matrix_dim <= 0)
        return;

#pragma omp parallel num_threads(omp_num_threads) default(none) shared(m, matrix_dim)
    {
        for (offset = 0; offset < matrix_dim; offset += BLOCK_SIZE) {
            int block_size = BLOCK_SIZE;
            int remain, num_tiles;

            if (offset + block_size > matrix_dim)
                block_size = matrix_dim - offset;

#pragma omp single
            {
                lud_diagonal_block(m, matrix_dim, offset, block_size);
            }

#pragma omp barrier

            remain = matrix_dim - (offset + block_size);
            num_tiles = (remain > 0) ? ((remain + BLOCK_SIZE - 1) / BLOCK_SIZE) : 0;

#pragma omp for schedule(static)
            for (int t = 0; t < num_tiles; t++) {
                int start = offset + block_size + t * BLOCK_SIZE;
                int tile_size = BLOCK_SIZE;

                if (start + tile_size > matrix_dim)
                    tile_size = matrix_dim - start;

                lud_perimeter_row(m, matrix_dim, offset, block_size, start, tile_size);
                lud_perimeter_col(m, matrix_dim, offset, block_size, start, tile_size);
            }

#pragma omp barrier

#pragma omp for collapse(2) schedule(static)
            for (int by = 0; by < num_tiles; by++) {
                for (int bx = 0; bx < num_tiles; bx++) {
                    int row_start = offset + block_size + by * BLOCK_SIZE;
                    int col_start = offset + block_size + bx * BLOCK_SIZE;
                    int row_block_size = BLOCK_SIZE;
                    int col_block_size = BLOCK_SIZE;

                    if (row_start + row_block_size > matrix_dim)
                        row_block_size = matrix_dim - row_start;
                    if (col_start + col_block_size > matrix_dim)
                        col_block_size = matrix_dim - col_start;

                    lud_internal_block(m, matrix_dim,
                                       row_start, row_block_size,
                                       col_start, col_block_size,
                                       offset, block_size);
                }
            }

#pragma omp barrier
        }
    }
}
